32	/**
33	 * Frontend sizing overrides for the backend-driven factory-quote detail grid
34	 * (SPEC_V2 §5k, hybrid model). The backend owns column identity/order; the
35	 * frontend only layers flex/minWidth/type/pinned onto specific columns by colId
36	 * so the row is gapless at any width — Note flexes to absorb the remainder, so
37	 * sizeColumnsToFit() must NOT be called (it fights flex). Keyed by both the live
38	 * colIds ('price', 'note') and the static-config variants ('quote_price',
39	 * 'vendor_note') so it works whichever the backend layout serves. All other
40	 * columns keep whatever the backend returned.
41	 */
42	export const DETAIL_COLUMN_SIZING: Record<string, Partial<ColDef>> = {
43	  name: { minWidth: 180, pinned: 'left' },
44	  price: { minWidth: 100, type: 'rightAligned' },
45	  quote_price: { minWidth: 100, type: 'rightAligned' },
46	  note: { flex: 1, minWidth: 200 },
47	  vendor_note: { flex: 1, minWidth: 200 },
48	};
