50	/** Merge the §5k sizing override (if any) onto a backend detail column def. */
51	export function applyDetailColumnSizing(col: any): any {
52	  if (!col || !col.colId) return col;
53	  const override = DETAIL_COLUMN_SIZING[col.colId];
54	  return override ? { ...col, ...override } : col;
55	}
