57	/**
58	 * Desired detail-grid column order (SPEC_V2 §5k):
59	 * Name · Price · Lead · CBM · Price Terms · FOB Country · FOB Port · Note.
60	 * Done in the frontend override step (no backend/DB change). Columns the backend
61	 * serves under a different colId are normalised via DETAIL_ORDER_ALIASES; any
62	 * column not listed sorts to the end, preserving the backend's relative order.
63	 */
64	export const DETAIL_COLUMN_ORDER: string[] = [
65	  'name', 'price', 'lead_time', 'cbm_pc', 'price_terms', 'fob_country', 'fob_port', 'note',
66	];
67	const DETAIL_ORDER_ALIASES: Record<string, string> = {
68	  quote_price: 'price',
69	  vendor_note: 'note',
70	};
71	
72	/** Reorder backend detail columns to DETAIL_COLUMN_ORDER (stable; unknowns last). */
73	export function orderDetailColumns(cols: any[]): any[] {
74	  if (!Array.isArray(cols)) return cols;
75	  const rank = (col: any): number => {
76	    const colId = col?.colId;
77	    const key = DETAIL_ORDER_ALIASES[colId] ?? colId;
78	    const i = DETAIL_COLUMN_ORDER.indexOf(key);
79	    return i === -1 ? Number.MAX_SAFE_INTEGER : i;
80	  };
81	  // Array.prototype.sort is stable, so unranked columns keep their backend order.
82	  return [...cols].sort((a, b) => rank(a) - rank(b));
83	}
