631	  /**
632	   * Filters columns based on user role
633	   * If a column has a 'roles' property, only show it if the user's role is included
634	   * If a column has no 'roles' property, it's visible to all users
635	   */
636	  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
637	    // If no role is provided, return all columns
638	    if (!role) {
639	      return colHeaders;
640	    }
641	
642	    return colHeaders.filter((col: any) => {
643	      // If column has no roles property or empty roles array, it's visible to all
644	      if (!col.roles || !Array.isArray(col.roles) || col.roles.length === 0) {
645	        return true;
646	      }
647	
648	      // Check if user's role is in the allowed roles array
649	      return col.roles.includes(role);
650	    });
651	  }
