715	  private applyColumnEditablePolicy(column: any): any {
716	    const originalEditable = column?.editable;
717	    const disableForRoles = Array.isArray(column?.disableForRoles) ? column.disableForRoles : [];
718	    const allowEditOverride = !!column?.allowEditOverride;
719	    return {
720	      ...column,
721	      editable: (params: any) => {
722	        if (disableForRoles.includes(this.getNormalizedRole())) {
723	          if (!allowEditOverride || !this.canCurrentSalesUserEditDetailCells()) {
724	            return false;
725	          }
726	        }
727	        const baseEditable =
728	          typeof originalEditable === 'function'
729	            ? !!originalEditable(params)
730	            : originalEditable !== false;
731	        if (!baseEditable) {
732	          return false;
733	        }
734	        return this.canCurrentSalesUserEditDetailCells();
735	      },
736	    };
737	  }
