1333	  /** Parse a quote price into a finite number, defaulting to 0 when unparseable. */
1334	  private toPrice(value: any): number {
1335	    const numValue = typeof value === 'number' ? value : parseFloat(value);
1336	    return Number.isFinite(numValue) ? numValue : 0;
1337	  }
1338	
1339	  /**
1340	   * A vendor quote row sorts to the bottom of the detail grid when it has no
1341	   * usable price (blank / zero / negative) or the factory declined to quote
1342	   * (req_status == 1). Used by the price default-sort comparator.
1343	   */
1344	  private isUnpricedOrDeclined(data: any): boolean {
1345	    if (!data) return true;
1346	    if (data.req_status == 1) return true;
1347	    const price = this.toPrice(data?.['Price']);
1348	    return price <= 0;
1349	  }
1350	
1351	  /**
1352	   * Wires the detail grid's default sort: price ascending as the primary sort,
1353	   * with unpriced/declined rows pushed to the bottom. Mutates the matching
1354	   * colDef in place. The comparator reads the row's `Price` directly so it is
1355	   * independent of the column's colId/field/valueGetter.
1356	   */
1357	  private applyDefaultPriceSort(colHeaders: any[]): void {
1358	    if (!Array.isArray(colHeaders)) return;
1359	    const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
1360	    // Prefer a visible price column; fall back to any price column.
1361	    const priceCol =
1362	      colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
1363	      colHeaders.find(c => isPriceCol(c));
1364	    if (!priceCol) return;
1365	
1366	    priceCol.sort = 'asc';
1367	    priceCol.sortIndex = 0;
1368	    priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
1369	      const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
1370	      const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
1371	      if (aBottom && bBottom) return 0;
1372	      if (aBottom) return 1;
1373	      if (bBottom) return -1;
1374	      return this.toPrice(nodeA?.data?.['Price']) - this.toPrice(nodeB?.data?.['Price']);
1375	    };
1376	  }
1377	
1378	  private convertToNumberOrNull(value: any): number | null {
1379	    // Ensure the value is a number or null
1380	    if (value === null || value === undefined || value === '') {
1381	      return null;
1382	    }
1383	    const numValue = typeof value === 'number' ? value : parseFloat(value);
1384	    return isNaN(numValue) ? null : numValue;
1385	  }
1386	}
