import { Component, EventEmitter, OnInit} from '@angular/core';
import { ICellRendererAngularComp, } from "ag-grid-angular";
import { MatDialog as MatDialog } from '@angular/material/dialog';
import { rfqDatepickerComponent } from '../datepicker/rfq-datepicker.component'
import { rfqAutocompleteComponent } from '../autocomplete/rfq-autocomplete.component';
import { VendorComponent } from '../vendor/vendor.component';
import { NewVendorComponent } from '../newVendor/newVendor.component';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar as MatSnackBar } from '@angular/material/snack-bar';
import { NumericEditor } from '../numericEditor/numericEditor.component';
import { rfqButtonComponent } from  '../rfq-button//rfq-button.component';
import { rfqEquation } from '../helpers/equation';
import { AuditLogComponent } from '../../helpers/auditLog/auditLog.component'
import { ColDef, GridApi, GridOptions,
  FirstDataRenderedEvent, GetRowIdParams, GetRowIdFunc, RowClassRules} from 'ag-grid-enterprise';
import { VendorDataInfoComponent } from '../vendor_data_info/vendor_data_info.component'
import { CustomTooltipComponent } from '../custom-tooltip/custom-tooltip.component';
import { RFQ_COLUMN_HEADERS_CONFIG } from 'src/app/helpers/ag-grid/rfq-grid/rfq.grid.config';
import { themePinkDetail } from 'src/app/helpers/ag-grid/grid-themes.config';
import { Theme } from 'ag-grid-enterprise';
import { ConfigService } from 'src/app/helpers/services/config.service';
import { AuthService } from '../../auth/helpers/auth.service';
import { LoaderService } from 'src/app/helpers/services/loader.service';
import { Observable } from 'rxjs';
import { AiSettingsService } from 'src/app/helpers/services/ai-settings.service';
import { computeFobAutofill } from '../helpers/fob-country-autofill';

export interface data {
  value: string;
}

/**
 * Frontend sizing overrides for the backend-driven factory-quote detail grid
 * (SPEC_V2 §5k, hybrid model). The backend owns column identity/order; the
 * frontend only layers flex/minWidth/type/pinned onto specific columns by colId
 * so the row is gapless at any width — Note flexes to absorb the remainder, so
 * sizeColumnsToFit() must NOT be called (it fights flex). Keyed by both the live
 * colIds ('price', 'note') and the static-config variants ('quote_price',
 * 'vendor_note') so it works whichever the backend layout serves. All other
 * columns keep whatever the backend returned.
 */
export const DETAIL_COLUMN_SIZING: Record<string, Partial<ColDef>> = {
  name: { minWidth: 180, pinned: 'left' },
  price: { minWidth: 100, type: 'rightAligned' },
  quote_price: { minWidth: 100, type: 'rightAligned' },
  note: { flex: 1, minWidth: 200 },
  vendor_note: { flex: 1, minWidth: 200 },
};

/** Merge the §5k sizing override (if any) onto a backend detail column def. */
export function applyDetailColumnSizing(col: any): any {
  if (!col || !col.colId) return col;
  const override = DETAIL_COLUMN_SIZING[col.colId];
  return override ? { ...col, ...override } : col;
}

/**
 * Desired detail-grid column order (SPEC_V2 §5k):
 * Name · Price · Lead · CBM · Price Terms · FOB Country · FOB Port · Note.
 * Done in the frontend override step (no backend/DB change). Columns the backend
 * serves under a different colId are normalised via DETAIL_ORDER_ALIASES; any
 * column not listed sorts to the end, preserving the backend's relative order.
 */
export const DETAIL_COLUMN_ORDER: string[] = [
  'name', 'price', 'lead_time', 'cbm_pc', 'price_terms', 'fob_country', 'fob_port', 'note',
];
const DETAIL_ORDER_ALIASES: Record<string, string> = {
  quote_price: 'price',
  vendor_note: 'note',
};

/** Reorder backend detail columns to DETAIL_COLUMN_ORDER (stable; unknowns last). */
export function orderDetailColumns(cols: any[]): any[] {
  if (!Array.isArray(cols)) return cols;
  const rank = (col: any): number => {
    const colId = col?.colId;
    const key = DETAIL_ORDER_ALIASES[colId] ?? colId;
    const i = DETAIL_COLUMN_ORDER.indexOf(key);
    return i === -1 ? Number.MAX_SAFE_INTEGER : i;
  };
  // Array.prototype.sort is stable, so unranked columns keep their backend order.
  return [...cols].sort((a, b) => rank(a) - rank(b));
}

export const onSetVendorData = new EventEmitter<any>()

@Component({
  selector: 'detail-cell-renderer',
  templateUrl: 'detail-cell-renderer.component.html',
  styleUrls: ['detail-cell-renderer.component.scss'],
  standalone: false
})
export class DetailCellRenderer implements ICellRendererAngularComp, OnInit {
  private gridColumnApi!: GridApi;
  /** RFQ brand theme for the factory-quote sub-grid (v35 Theming API, SPEC_V2 §5k). */
  detailTheme: Theme = themePinkDetail;
  public rowClassRules: RowClassRules;
  vendors: any[]
  frameworkComponents: any;
  params: any;
  masterGridApi: any
  rowId: any;
  getRowStyle;
  defaultColDef: any;
  colDefs: any;
  gridInfo: GridApi;
  gridOptions: GridOptions = {
    rowSelection: {
      mode: 'multiRow',
      headerCheckbox: true,
    },
    cellSelection: { handle: { mode: 'fill', direction: 'y' }, suppressMultiRanges: true },
    groupDefaultExpanded: 0,
  };
  rowData: any;
  columnsToAutoSize: string[] = [];
  rfqDatepickerComponent: rfqDatepickerComponent
  rfqAutocompleteComponent: rfqAutocompleteComponent
  getRowId: GetRowIdFunc = (params: GetRowIdParams) => {
    const quote_id = params?.data?.quote_id;
    if (quote_id) return String(quote_id);
    const vendor = params?.data?.Vendor;
    const candidate = vendor?.factory_nickname?.title ?? vendor?.factory_nickname ?? vendor?.id ?? params?.data?.priceCode;
    return String(candidate ?? Math.random().toString(36).slice(2));
  };
  role: any = 'vendor';
  currentUserId: number | null = null;
  allowedUserIdsToViewPrice: number[] = [];
  allowAccessToSalesUsers: number[] = [];
  enableSalesDetailEditing = false;
  allowEditSalesUsersInDetailRenderer: number[] = [];
  colHeaders: any[]
  selectedVendors: any = []
  masterColumnDefs: any = [];
  fobCountries: string[] = [];
  /** Cached factory_nickname → factory_country lookup loaded once per detail renderer. */
  private factoryCountryMap: Record<string, string> = {};
  cellMouseOverActive: boolean;
  displayValue: any;
  topPos: any;
  leftPos: any;
  gridDomLayout: 'normal' | 'autoHeight' = 'normal';
  // called on init
  constructor(
    public dialog: MatDialog,
    private itemService: itemService,
    private _snakcbar: MatSnackBar,
    private equation: rfqEquation,
    private configService: ConfigService,
    private authService: AuthService,
    private loaderService: LoaderService,
    private aiSettings: AiSettingsService,
  ) {
    // this.getRowNodeId = function (data) {
    //   return data.Vendor.factory_nickname;
    // };

  }
  ngOnInit(): void {

  }
  agInit(params: any): void {
    this.role = window['role']
    this.gridDomLayout = this.role === 'vendor' ? 'autoHeight' : 'normal';
    window['DialogData'] = false;
    window['dataWasChanged']
    window['dialog'] = this.dialog;
    window['onCellValueChanged'] = this.onCellValueChanged.bind(this);
    this.frameworkComponents = {
      'numericCellEditor': NumericEditor, 'autoCompelete': rfqAutocompleteComponent, 'datePicker': rfqDatepickerComponent, 'button': rfqButtonComponent,
      customTooltip: CustomTooltipComponent
    };
    this.params = params;
    this.allowedUserIdsToViewPrice = (this.configService.get('allowedUserIdsToViewPrice') as number[]) || [];
    this.allowAccessToSalesUsers = (this.configService.get('allowAccessToSalesUsers') as number[]) || [];
    this.enableSalesDetailEditing = !!this.configService.get('enableSalesDetailEditing');
    this.allowEditSalesUsersInDetailRenderer =
      (this.configService.get('allowEditSalesUsersInDetailRenderer') as number[]) || [];

    this.masterGridApi = params;
    this.rowId = params.node.id;
    // Load master column headers from config file
    this.masterColumnDefs = [...RFQ_COLUMN_HEADERS_CONFIG.columnDefs];
    this.masterColumnDefs = this.filterColumnsByRole(this.masterColumnDefs, this.role);
    // Preload FOB countries first, then load grid headers
    this.authService.getUserFromToken().then((user: any) => {
      this.currentUserId = user?.user_id ?? null;
      this.itemService.getFOBCountry().subscribe((countries: unknown) => {
        const countryList = Array.isArray(countries) ? countries : [];
        this.fobCountries = countryList
          .map((c: any) => c?.FOBCountry_title ?? c?.dataValues?.FOBCountry_title)
          .filter(Boolean);
        this.loadDetailColumnHeaders().subscribe((colHeaders: any[]) => {
          this.configureDetailColumnHeaders(colHeaders);
        });
      });
      // Factory → country map, used to pre-fill FOB Country when the user picks
      // a factory in the Name column. Non-fatal if it fails (we just don't auto-fill).
      this.aiSettings.getFactoryCountryMap().subscribe({
        next: res => { this.factoryCountryMap = res?.map ?? {}; },
        error: () => { this.factoryCountryMap = {}; },
      });
    });
    this.rowData = params.data.Vendors;

    this.defaultColDef = {
      sortable: true,
      editable: (params: any) => this.canCurrentSalesUserEditDetailCells(),
      resizable: true,
      filter: false,
    };

    this.rowData = params.data.Vendors;
    this.rowClassRules = {
      'responded': 'data.req_status == 2',
      'passed': 'data.req_status == 1',
      'empty': 'data.req_status == null'
    }
  }

  /** Detail columns from API (GridLayout / role access). Config migration later. */
  private loadDetailColumnHeaders(): Observable<any[]> {
    return this.itemService.getGridHeader({ grid_id: 'rfq_detail' }) as Observable<any[]>;
  }

  private configureDetailColumnHeaders(colHeaders: any[]): void {
    function formatNumber(number) {
      return Number.parseFloat(number).toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1,');
    }
    function formatDate(input) {
      if (input == null) return '';
      if (input.includes('-')) {
        const datePart = input.match(/\d+/g);
        const year = datePart[0].substring();
        const month = datePart[1];
        const day = datePart[2];
        return month + '/' + day + '/' + year;
      }
      return input;
    }
    function measurementFormatter(params) {
      if (params.value) {
        return formatNumber(params.value) + ' cm';
      }
    }
    // "2025-05-05" / "05/05/2025" -> "May 5 2025" for the re-quote tooltip.
    // Parses the parts manually to avoid timezone shifts from new Date(string).
    function formatQuotedDate(input) {
      if (input == null || input === '') return '';
      const months = ['January','February','March','April','May','June',
        'July','August','September','October','November','December'];
      const parts = String(input).match(/\d+/g);
      if (!parts || parts.length < 3) return String(input);
      let year, month, day;
      if (String(input).includes('-')) {
        // YYYY-MM-DD
        [year, month, day] = parts;
      } else {
        // MM/DD/YYYY
        [month, day, year] = parts;
      }
      const monthName = months[Number(month) - 1] || month;
      return `${monthName} ${Number(day)} ${year}`;
    }
    function currencyFormatter(params) {
      if (params.value) {
        return '$' + formatNumber(params.value);
      }
    }

    this.colHeaders = colHeaders;
    this.columnsToAutoSize = [];
    const shouldHidePrice = this.shouldHideSalesPriceColumns();
    for (var i = 0; i < colHeaders.length; i++) {
        this.removeLegacySelectionColumnFlags(colHeaders[i]);
        const colId = colHeaders[i]?.colId;
        if (shouldHidePrice && (colId === 'price' || colId === 'quote_price')) {
          colHeaders[i].hide = true;
          // Single source of truth for editability is applyColumnEditablePolicy().
          colHeaders[i].disableForRoles = ['production', 'sales', 'sales_manager'];
        }
        this.applySalesDetailColumnAccessOverride(colHeaders[i], colId);
        colHeaders[i]['tooltipValueGetter'] = (params) => {
          return params?.value;
        }
        if (colHeaders[i].colId == 'note' || colHeaders[i].colId == 'vendor_note') {
          colHeaders[i].flex = 2;
        } else if(colHeaders[i].colId == 'name'){
          colHeaders[i].flex = 1;
          colHeaders[i].maxWidth = 200;
        } else {
          colHeaders[i].maxWidth = 120;
          this.columnsToAutoSize.push(colHeaders[i].field);
        }
        if (colHeaders[i].colId == 'name') {
          // Secondary sort: alphabetical tiebreaker once the price column
          // (sortIndex 0, wired in applyDefaultPriceSort) has ordered the rows.
          colHeaders[i]['sort'] = 'asc';
          colHeaders[i]['sortIndex'] = 1;
          colHeaders[i]['suppressFillHandle'] = true
          colHeaders[i]['cellEditor'] = 'autoCompelete'
          colHeaders[i]['valueGetter'] = params => {
            const vendor = params?.data?.Vendor;
            const nickname = vendor?.factory_nickname;
            if (nickname != null && nickname !== undefined) {
              if (typeof nickname === 'object' && 'title' in nickname) {
                return nickname.title || '';
              } else {
                return nickname;
              }
            }
            return '';
          }

          colHeaders[i]['valueSetter'] = params => {
            if (!params.data.Vendor) params.data.Vendor = {} as any;
            params.data.Vendor.factory_nickname = params.newValue;

            // Auto-fill FOB Country from the factory's stored country. Only
            // when the cell is currently empty — never clobber an explicit
            // user override on a quote row.
            const nick = typeof params.newValue === 'string'
              ? params.newValue
              : (params.newValue?.title ?? '');
            const autofill = computeFobAutofill(
              params.data['FOB Country'],
              nick,
              this.factoryCountryMap,
            );
            if (autofill.fobCountry) {
              params.data['FOB Country'] = autofill.fobCountry;
              // Trigger the same recalc/persistence path the FOB Country
              // valueSetter would, so downstream listeners see the change.
              this.onCellValueChanged({ ...params, colDef: { field: 'FOB Country' } });
            }
            return true;
          }
        } else if (colHeaders[i].colId == 'price') {
          var price_col_name = colHeaders[i].field;
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueFormatter = currencyFormatter
          // Stale-price flag (legacy 'price' colId — mirrors the 'quote_price' branch).
          colHeaders[i].cellClassRules = {
            'requote-requested-cell': (params) => !!params.data?.requote_requested
          };
          colHeaders[i].tooltipValueGetter = (params) => {
            if (params?.data?.requote_requested) {
              return `报价 - Quoted ${formatQuotedDate(params.data['quote_date'])}`;
            }
            return params?.value;
          };
        } else if (colHeaders[i].colId == 'cbm_pc') {
          var cbm_col_name = colHeaders[i].field;
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueParser = (params) => this.convertToNumberOrNull(params.newValue);
          colHeaders[i].valueSetter = params => {
            params.data[cbm_col_name] = this.convertToNumberOrNull(params.newValue);

            var rowNode = this.masterGridApi.api.getRowNode(params.data.priceCode)!;
            if (rowNode.data[this.getMasterFiledName('chosen_vendor')]) {
              if (rowNode.data[this.getMasterFiledName('chosen_vendor')].title == params.data.Vendor.factory_nickname) {
                rowNode.setDataValue('CBM/pc', params.newValue)
              }
            }
            params.data.masterGridChange = false;


            return true;
          }
        } else if (colHeaders[i].colId == 'carton_length') {
          let col_name = colHeaders[i].field;
          colHeaders[i].cellStyle = function (params) {
            if (!params.data['carton_length'] && params.data['Price'] && params.data['req_status'] == 2 || params.data['req_status'] == 1) {
              return { background: '#fd8e8e' };
            } else if (params.data['carton_length'] && params.data['Price'] && params.data['req_status'] == 2) {
              return { background: '#8ac58a' };;
            }
          }
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueFormatter = measurementFormatter
          colHeaders[i].valueGetter = params => {
            if (params.data['carton_length']) {
              return params.data['carton_length'];
            }
          }
          colHeaders[i].valueSetter = params => {
            if (params.newValue == "") {
              params.newValue = null
              this.onCellValueChanged(params)
            }
            params.data['cbm_modified'] = true;
            params.data['carton_length'] = params.newValue;

            return params.data['carton_length'];
          }
        } else if (colHeaders[i].colId == 'carton_width') {
          let col_name = colHeaders[i].field;
          colHeaders[i].cellStyle = function (params) {
            if (!params.data['carton_width'] && params.data['Price'] && params.data['req_status'] == 2 || params.data['req_status'] == 1) {
              return { background: '#fd8e8e' };
            } else if (params.data['carton_width'] && params.data['Price'] && params.data['req_status'] == 2) {
              return { background: '#8ac58a' };;
            }
          }
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueFormatter = measurementFormatter
          colHeaders[i].valueGetter = params => {
            if (params.data['carton_width']) {
              return params.data['carton_width'];
            }
          }
          colHeaders[i].valueSetter = params => {
            if (params.newValue == "") {
              params.newValue = null
              this.onCellValueChanged(params)
            }
            params.data['cbm_modified'] = true;
            params.data['carton_width'] = params.newValue;
            return params.data['carton_width'];
          }
        } else if (colHeaders[i].colId == 'carton_height') {
          let col_name = this.getDetailFiledName('carton_height')
          let price_col = this.getDetailFiledName('price')
          colHeaders[i].cellStyle = function (params) {
            if (!params.data['carton_height'] && params.data['Price'] && params.data['req_status'] == 2 || params.data['req_status'] == 1) {
              return { background: '#fd8e8e' };
            } else if (params.data['carton_height'] && params.data['Price'] && params.data['req_status'] == 2) {
              return { background: '#8ac58a' };;
            }
          }
          colHeaders[i].valueGetter = params => {
            if (params.data['carton_height']) {
              return params.data['carton_height'];
            }
          }
          colHeaders[i].valueSetter = params => {
            if (params.newValue == "") {
              params.newValue = null
              this.onCellValueChanged(params)
            }
            params.data['cbm_modified'] = true;
            params.data['carton_height'] = params.newValue;
            return params.data['carton_height'];
          }
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueFormatter = measurementFormatter
        } else if (colHeaders[i].colId == 'quote_price') {
          let col_name = colHeaders[i].field;
          colHeaders[i].valueGetter = params => {
            if (params.data['Price']) {
              return params.data['Price'];
            }
          }
          colHeaders[i].valueSetter = params => {
            params.data['Price'] = params.newValue;
            params.data['cbm_modified'] = true;
            if (params.newValue) params.data['req_status'] = 2
            // A fresh price clears any pending re-quote request (orange highlight).
            params.data['requote_requested'] = false;
            this.onCellValueChanged(params)
            return params.data['Price'];
          }
          colHeaders[i].cellEditor = "numericCellEditor"
          colHeaders[i].valueFormatter = currencyFormatter
          // Stale-price flag: highlight the old price orange in both the internal
          // and vendor views when Sourcing has requested a fresh quote.
          colHeaders[i].cellClassRules = {
            'requote-requested-cell': (params) => !!params.data?.requote_requested
          };
          // Bilingual tooltip showing when the (now-stale) price was originally
          // quoted, e.g. "报价 - Quoted May 5 2025". Overrides the generic
          // value tooltip set at the top of this loop.
          colHeaders[i].tooltipValueGetter = (params) => {
            if (params?.data?.requote_requested) {
              return `报价 - Quoted ${formatQuotedDate(params.data['quote_date'])}`;
            }
            return params?.value;
          };
        } else if (colHeaders[i].colId == 'vendor_note' || colHeaders[i].colId == 'note') {
          colHeaders[i].valueGetter = params => {
            if (params.data['Note']) {
              return params.data['Note'];
            }
          }
          colHeaders[i].valueSetter = params => {
            if (params.newValue == "") {
              params.newValue = null
              this.onCellValueChanged(params)
            }
            params.data['Note'] = params.newValue;
            return params.data['Note'];
          }
        } else if (colHeaders[i].colId == 'lead_time') {
          colHeaders[i].cellEditor = "numericCellEditor";
          colHeaders[i].valueSetter = params => {
            if (params.newValue == "") {
              params.newValue = null;
            }
            params.data['Lead Time (days)'] = params.newValue;
            this.onCellValueChanged(params);
            return true;
          };
        } else if (colHeaders[i].colId == 'price_terms') {
          colHeaders[i].cellEditor = 'agSelectCellEditor';
          colHeaders[i].cellEditorParams = {
            values: ['FOB', 'mDDP', 'LDP', 'DDP']
          };
          colHeaders[i].valueSetter = params => {
            params.data['Price Terms'] = params.newValue;
            this.onCellValueChanged(params);
            return true;
          };
        } else if (colHeaders[i].colId == 'fob_country') {
          colHeaders[i].cellEditor = 'agSelectCellEditor';
          colHeaders[i].cellEditorParams = {
            values: this.fobCountries || []
          };
          colHeaders[i].valueGetter = params => {
            return params.data['FOB Country'];
          };
          colHeaders[i].valueSetter = params => {
            params.data['FOB Country'] = params.newValue;
            this.onCellValueChanged(params);
            return true;
          };
        } else if (colHeaders[i].colId == 'fob_port') {
          colHeaders[i].valueSetter = params => {
            params.data['FOB Port'] = params.newValue;
            this.onCellValueChanged(params);
            return true;
          };
        } else if (colHeaders[i].colId == 'submite_btn') {
          colHeaders[i].cellRenderer = "button"
          colHeaders[i].editable = false
          colHeaders[i].width = 160
          colHeaders[i].maxWidth = 200
          this.getRowStyle = params => {
            if (params.data['req_status'] == 1) {
              return { background: '#fb080875' };
            } else if (params.data['req_status'] == 2) {
              return { background: '#00800075' };
            }
          };
        } else if (colHeaders[i].colId == 'quote_date') {
          let col_name = colHeaders[i].field;
          colHeaders[i].valueGetter = params => {
            if (params.data['quote_date']) {
              return params.data['quote_date'];
            }
          }
          colHeaders[i].valueSetter = params => {
            params.data['quote_date'] = params.newValue;
            return params.data['quote_date'];
          }
          colHeaders[i]['cellEditor'] = 'datePicker'
          colHeaders[i]['cellRenderer'] = (data) => {
            return formatDate(data.value);
          }

          colHeaders[i]['filterParams'] = {
            comparator: function (filterLocalDateAtMidnight, cellValue) {
              var dateAsString = cellValue;
              dateAsString = formatDate(cellValue)
              if (dateAsString == null) return -1;
              var dateParts = dateAsString.split('/');
              var cellDate = new Date(
                Number(dateParts[2]),
                Number(dateParts[0] - 1),
                Number(dateParts[1])
              );
              if (filterLocalDateAtMidnight.getTime() === cellDate.getTime()) {
                return 0;
              }
              if (cellDate < filterLocalDateAtMidnight) {
                return -1;
              }
              if (cellDate > filterLocalDateAtMidnight) {
                return 1;
              }

            },
            browserDatePicker: true,
            minValidYear: 2000,
            maxValidYear: 2050,
          };
          colHeaders[i]['comparator'] = this.dateComparator
        }
      }

    // Default-sort the detail grid by factory price, lowest first. The price
    // column's colId varies by backend layout ('quote_price' or legacy 'price'),
    // so target whichever visible one exists and make it the primary sort. Name
    // (sortIndex 1) stays as the alphabetical tiebreaker. Rows with no usable
    // price (blank / zero) or where the factory declined to quote
    // (req_status == 1) are always sunk to the bottom.
    this.applyDefaultPriceSort(colHeaders);

    colHeaders = colHeaders.map((col: any) => this.applyColumnEditablePolicy(col));
    colHeaders = colHeaders.map(col => ({ ...col, filter: null }));
    // Reorder to the §5k order, then layer the sizing overrides on top of the
    // backend column defs (Note flexes, Name pinned, Price right-aligned).
    // Frontend-only — no backend/DB change. Applied last so they win.
    colHeaders = orderDetailColumns(colHeaders);
    colHeaders = colHeaders.map(col => applyDetailColumnSizing(col));
    this.colDefs = colHeaders;

    if (
      this.gridInfo &&
      typeof this.gridInfo.isDestroyed === 'function' &&
      !this.gridInfo.isDestroyed()
    ) {
      for (let j = 0; j < this.colDefs.length; j++) {
        if (this.colDefs[j]?.colId === 'fob_country') {
          this.colDefs[j].cellEditorParams = { values: this.fobCountries || [] };
        }
      }
      this.gridInfo.setGridOption('columnDefs', this.colDefs);
      this.syncVendorDetailHeight();
    }
  }

  private removeLegacySelectionColumnFlags(colDef: any): void {
    if (!colDef) return;
    delete colDef.checkboxSelection;
    delete colDef.headerCheckboxSelection;
    delete colDef.headerCheckboxSelectionFilteredOnly;
    delete colDef.headerCheckboxSelectionCurrentPageOnly;
    delete colDef.showDisabledCheckboxes;
  }

  /**
   * Filters columns based on user role
   * If a column has a 'roles' property, only show it if the user's role is included
   * If a column has no 'roles' property, it's visible to all users
   */
  private filterColumnsByRole(colHeaders: any[], role: string): any[] {
    // If no role is provided, return all columns
    if (!role) {
      return colHeaders;
    }

    return colHeaders.filter((col: any) => {
      // If column has no roles property or empty roles array, it's visible to all
      if (!col.roles || !Array.isArray(col.roles) || col.roles.length === 0) {
        return true;
      }

      // Check if user's role is in the allowed roles array
      return col.roles.includes(role);
    });
  }

  /**
   * Separate override: allow configured sales users to view vendor-quote columns.
   */
  private applySalesDetailColumnAccessOverride(column: any, colId: string): void {
    const allowedColumns = new Set(['price', 'quote_price', 'lic_price', 'price_terms']);
    const normalizedRole = String(this.role ?? '').trim().toLowerCase();
    const isSalesRole = normalizedRole === 'sales' || normalizedRole === 'sales_manager';
    const normalizedCurrentUserId = this.currentUserId != null ? Number(this.currentUserId) : null;
    const normalizedAllowList = (this.allowAccessToSalesUsers || []).map((id: any) => Number(id));
    const isAllowedSalesUser =
      isSalesRole &&
      normalizedCurrentUserId != null &&
      normalizedAllowList.includes(normalizedCurrentUserId);

    if (isAllowedSalesUser && allowedColumns.has(colId)) {
      if ((colId === 'price' || colId === 'quote_price') && this.shouldHideSalesPriceColumns()) {
        return;
      }
      column.hide = false;
      column.allowEditOverride = true;
    }
  }

  private shouldHideSalesPriceColumns(): boolean {
    const normalizedRole = this.getNormalizedRole();
    const isRestrictedRole = normalizedRole === 'production' || this.isSalesRole();
    if (!isRestrictedRole) {
      return false;
    }
    const normalizedCurrentUserId = this.currentUserId != null ? Number(this.currentUserId) : null;
    const normalizedAllowedUserIdsToViewPrice = (this.allowedUserIdsToViewPrice || []).map((id: any) =>
      Number(id),
    );
    return (
      normalizedCurrentUserId == null ||
      !normalizedAllowedUserIdsToViewPrice.includes(normalizedCurrentUserId)
    );
  }

  private isSalesRole(): boolean {
    const normalizedRole = this.getNormalizedRole();
    return normalizedRole === 'sales' || normalizedRole === 'sales_manager';
  }

  private getNormalizedRole(): string {
    return String(this.role ?? '').trim().toLowerCase();
  }

  private canCurrentSalesUserEditDetailCells(): boolean {
    if (!this.isSalesRole()) {
      return true;
    }
    if (!this.enableSalesDetailEditing) {
      return false;
    }
    const normalizedCurrentUserId = this.currentUserId != null ? Number(this.currentUserId) : null;
    const normalizedAllowList = (this.allowEditSalesUsersInDetailRenderer || []).map((id: any) =>
      Number(id),
    );
    return normalizedCurrentUserId != null && normalizedAllowList.includes(normalizedCurrentUserId);
  }

  private applyColumnEditablePolicy(column: any): any {
    const originalEditable = column?.editable;
    const disableForRoles = Array.isArray(column?.disableForRoles) ? column.disableForRoles : [];
    const allowEditOverride = !!column?.allowEditOverride;
    return {
      ...column,
      editable: (params: any) => {
        if (disableForRoles.includes(this.getNormalizedRole())) {
          if (!allowEditOverride || !this.canCurrentSalesUserEditDetailCells()) {
            return false;
          }
        }
        const baseEditable =
          typeof originalEditable === 'function'
            ? !!originalEditable(params)
            : originalEditable !== false;
        if (!baseEditable) {
          return false;
        }
        return this.canCurrentSalesUserEditDetailCells();
      },
    };
  }

