  private syncVendorDetailHeight(): void {
    if (this.role !== 'vendor' || !this.params?.node || !this.params?.api || !this.gridInfo) {
      return;
    }

    setTimeout(() => {
      const rowCount = Math.max(this.gridInfo.getDisplayedRowCount(), 1);
      const themeSizes = this.gridInfo.getSizesForCurrentTheme?.();
      const rowHeight = themeSizes?.rowHeight || 42;
      const headerHeight = themeSizes?.headerHeight || 48;
      const toolbarAndPadding = 130;
      const detailHeight = Math.max((rowCount * rowHeight) + headerHeight + toolbarAndPadding, 220);

      this.params.node.setRowHeight(detailHeight);
      this.params.api.onRowHeightChanged();
    }, 0);
  }
  dateComparator(date1, date2, nodeA, nodeB, isInverted) {
    function formatDate(input) {
      if (input == null) return ''
      if (input.includes("-")) {
        var datePart = input.match(/\d+/g),
          year = datePart[0].substring(), // get only two digits
          month = datePart[1], day = datePart[2];
        return month + '/' + day + '/' + year;
      } else {
        return input
      }
    }
  }
