  async onBtnNewVendor() {
    const existingVendorIds = (this.params?.node?.data?.Vendors || [])
      .map(v => v?.Vendor?.id)
      .filter(id => id != null);
    const dialogRef = this.dialog.open(VendorComponent, { data: { vendors: existingVendorIds }, height: '95vh', width: '95vw' });
    dialogRef.afterClosed().subscribe(async (result) => {

      if (result) {
        this.loaderService.increment();
        try {
          this.vendors = result;
          var oldData = this.params.node.data;
          const filtered = result;

          if (filtered.length) {
            filtered.forEach((element) => {
              element.priceCode = this.params.node.data[this.getMasterFiledName('price_code')]
            });

            const addedQuotes: any = await this.itemService.addingVendor(filtered).toPromise();

            oldData.Vendors = oldData.Vendors || [];
            filtered.forEach((element, index) => {
              let generatedQuoteId = addedQuotes && addedQuotes[index] ? addedQuotes[index].quote_id : null;
              oldData.Vendors.push({
                priceCode: element.priceCode,
                'CBM/pc': null,
                Price: null,
                Status: null,
                Note: null,
                Vendor: element,
                quote_id: generatedQuoteId
              })
            });

            const resFieldName = this.getMasterFiledName('res');
            const resValue = resFieldName ? oldData[resFieldName] : null;
            if (resValue) {
              const resArray = String(resValue).split('/');
              const currentCount = Number.parseInt(resArray[resArray.length - 1], 10);
              if (!Number.isNaN(currentCount)) {
                oldData[resFieldName] =
                  `${resArray[0]}/${currentCount + filtered.length}`;
              }
            }
            this.params.api.applyTransaction({ update: [oldData] });

            if (typeof this.params.onFactoriesAdded === 'function') {
              try {
                await this.params.onFactoriesAdded(oldData);
              } catch {
                this._snakcbar.open(
                  'Factories added, but Step could not be updated to @factories. You can change Step manually.',
                  'close',
                  { duration: 6000 }
                );
              }
            }
          }
          this.params.api.applyTransaction({ update: [oldData] });
          for (var i = 0; filtered.length > i; i++) {
            try {
              await this.itemService.sendPriceReq({ id: filtered[i].id, rfqItem_priceCode: filtered[i].priceCode, sendEmail: true }).toPromise();
            } catch {
              // Price request failure must not block Step update (already applied above).
            }
          }
          this.params.node.setExpanded(true);
          this.params.api.resetRowHeights();
        } catch (error) {
          this._snakcbar.open('Failed to add selected factories. Please try again.', 'close');
        } finally {
          this.loaderService.decrement();
        }
      }
    });
  }

  async deleteRow() {
    let detailId = this.params.node.id
    let gridApi = this.params.api.getDetailGridInfo(detailId)
    let selectedRows = gridApi.api.getSelectedNodes();
    let priceCode = detailId.replace('detail_', '')
    let oldData = gridApi.rowData;
    if (selectedRows.length > 0) {
      for (var i = 0; gridApi.rowData.length > i; i++) {
        for (var j = 0; selectedRows.length > j; j++) {
          if ((oldData[i].quote_id && oldData[i].quote_id === selectedRows[j].data.quote_id) || (!oldData[i].quote_id && oldData[i] === selectedRows[j].data)) {
            this.itemService.deleteRFQItemVendor({ quote_id: selectedRows[j].data.quote_id, id: selectedRows[j].data.Vendor.id, priceCode: priceCode }).subscribe(async (result) => {
              this.params.api.applyTransaction({ update: [this.params.data] });
            })
            let gridId = gridApi.id.replace('detail_', '')
            var rowNode = this.masterGridApi.api.getRowNode(gridId)!;
            let chosen_vendor = rowNode.data[this.getMasterFiledName('chosen_vendor')]
            if (chosen_vendor) {
              if (chosen_vendor.id == selectedRows[j].data.Vendor.factory_nickname) {
                rowNode.setDataValue(this.getMasterFiledName('cbm_pc'), '0');
                rowNode.setDataValue(this.getMasterFiledName('chosen_vendor'), '');
              }
            }
            let filedName = this.getMasterFiledName('res')
            let res = this.params.data[filedName]
            let resArray = res.split('/')
            if (oldData[i].req_status != 1) {
              let newRes = resArray[0] + "/" + (parseInt(resArray[resArray.length - 1]) - 1).toString()
              this.params.data[filedName] = newRes
              this.params.api.applyTransaction({ update: [this.params.data] });
            }
            // gridApi.api.applyTransaction({ remove: [oldData[i]] });
            oldData.splice(i, 1);
          }
        }
      }

      this.params.api.resetRowHeights();
    } else {
      this._snakcbar.open('Please select a vendor', 'close')
    }
  }

  async onInviteOneTimeVendor() {
    const detailId = this.params.node.id.replace('detail_', '');
    const dialogRef = this.dialog.open(NewVendorComponent, { disableClose: true, data: {status: false} });
    dialogRef.afterClosed().subscribe(async (result: any) => {
      if (result?.status) {
        try {
          // use the created factory returned from dialog (may be temporary and not in getAllVendors)
          const newFactory = result.data;
          if (!newFactory?.id) { this._snakcbar.open('Vendor already exists.', 'close'); return; }
          // assign vendor to this RFQ item
          const payload = [{ ...newFactory, priceCode: detailId }];
          await (this.itemService.addingVendor(payload) as any).toPromise();
          // update UI detail grid immediately
          const oldData = this.params.node.data;
          oldData.Vendors = oldData.Vendors || [];
          oldData.Vendors.push({
            priceCode: detailId,
            'CBM/pc': null,
            Price: null,
            Status: null,
            Note: null,
            Vendor: newFactory
          });
          this.params.api.applyTransaction({ update: [oldData] });
          // send one-time link email
          await (this.itemService.sendPriceReq({ id: newFactory.id, rfqItem_priceCode: detailId, sendEmail: true }) as any).toPromise();
          this._snakcbar.open('One-time quote link sent.', 'close');
          // update res counter on master row
          let filedName = this.getMasterFiledName('res')
          let res = this.params.data[filedName]
          if (res) {
            let resArray = res.split('/')
            let newRes = resArray[0] + "/" + (parseInt(resArray[resArray.length - 1]) + 1).toString()
            this.params.data[filedName] = newRes
            this.params.api.applyTransaction({ update: [this.params.data] });
          }
          // expand and refresh
          this.params.node.setExpanded(true);
          this.params.api.resetRowHeights();
        } catch (e) {
          this._snakcbar.open('Failed to send invite. Try again.', 'close');
        }
      }
    });
  }

  async onBtnAddQuote() {
    let detailId = this.params.node.id.replace('detail_', '');
    let existingVendors = this.params?.node?.data?.Vendors || [];

    // Find the current user's vendor object in the existing rows
    // Often, a vendor only sees their own rows, so we can take the first valid vendor object.
    let currentVendorObj = existingVendors.find(v => v?.Vendor?.id);
    if (!currentVendorObj || !currentVendorObj.Vendor) {
      this._snakcbar.open('Error finding your factory details. Please refresh.', 'close');
      return;
    }

    let hasEmptyNote = existingVendors.some(v => !v.Note || String(v.Note).trim() === '');
    if (hasEmptyNote) {
      this._snakcbar.open('Please add notes to your existing quotes before adding a new one.', 'close');
      return;
    }

    try {
      // The backend expects the factory ID in the `id` field
      // When a row is mapped in AG Grid, currentVendorObj.Vendor typically holds the factory object
      const factorId = currentVendorObj.Vendor.id || currentVendorObj.std_vendor_id_fk;

      const payload = [{ 
        ...currentVendorObj.Vendor, 
        id: factorId,
        priceCode: detailId 
      }];

      const addedQuotes: any = await this.itemService.addingVendor(payload).toPromise();

      let generatedQuoteId = addedQuotes && addedQuotes[0] ? addedQuotes[0].quote_id : null;
      let newRow = {
        priceCode: detailId,
        'CBM/pc': null,
        Price: null,
        Status: null,
        Note: null,
        Vendor: currentVendorObj.Vendor,
        std_vendor_id_fk: currentVendorObj.std_vendor_id_fk,
        quote_id: generatedQuoteId
      };

      existingVendors.push(newRow);

      // Do not increment the master row 'res' counter because it counts unique vendors
      // and this vendor is already counted. Just apply the transaction to the detail grid.
      this.params.api.applyTransaction({ update: [this.params.node.data] });
      this.params.api.resetRowHeights();
      this._snakcbar.open('New quote line added successfully.', 'close');
    } catch (e) {
      this._snakcbar.open('Failed to add quote line. Please try again.', 'close');
      console.error(e);
    }
  }

  async onCellValueChanged(params) {
    if (!this.canCurrentSalesUserEditDetailCells()) {
      return;
    }
    let data;
    let price_code_field_name = this.getMasterFiledName('price_code');
    if (window['DialogData']) {
      data = params.node.data
      let currentNode = this.params.api.getRowNode(data.priceCode).data
      data.casePack = currentNode[this.getMasterFiledName('case_pack')]
    } else {
      data = params.data

      if (params.column) {
        const colDef = params.column.getColDef();
        if (colDef.colId == 'price_code' && params.newValue) {
          data.quote_accepted = true
          price_code_field_name = colDef.field
        }
      }
      data.priceCode = this.params.node.data[price_code_field_name]
      data.casePack = this.params.node.data[this.getMasterFiledName('case_pack')]
    }
    data.role = this.role

    this.itemService.updateVendor(data).subscribe(async (res: any) => {
      //onSetVendorData.emit(res)
      let rowData = this.params.api.getRowNode(this.params.node.data[price_code_field_name]).data.Vendors
      if (window['DialogData']) {
        rowData = this.params.api.getRowNode(data.priceCode).data.Vendors
      }
      window['DialogData'] = false;
      for (var i = 0; rowData.length > i; i++) {
        const isMatchByQuoteId = rowData[i].quote_id && rowData[i].quote_id === res.quote_id;
        const isMatchByNicknameIfNoQuoteId = !rowData[i].quote_id && rowData[i].Vendor.factory_nickname === res.Vendor.factory_nickname;

        if (isMatchByQuoteId || isMatchByNicknameIfNoQuoteId) {
          rowData[i] = res;
        }
      }
      params.api.setGridOption("rowData", rowData)
      setTimeout(() => {
        if (this.columnsToAutoSize && this.columnsToAutoSize.length > 0) {
          params.api.autoSizeColumns(this.columnsToAutoSize);
        }
      });
    })
  }

