  async onSelectVendor() {
    let selectedVendor = this.getSelectedRowData()
    let cbms = [];
    if (selectedVendor.length == 1) {
      if(!selectedVendor[0]['Price'] || !selectedVendor[0]['CBM/pc']) this._snakcbar.open('Warning: Price or CBM/pc is missing!', 'close' ,{duration: 5000})
      let data = this.params.node.data
      for (var i = 0; data.Vendors.length > i; i++) {
        if (data.Vendors[i]['CBM/pc'] && parseFloat(data.Vendors[i]['CBM/pc']) > 0)
          cbms.push(data.Vendors[i]['CBM/pc']);
      }

      data['Chosen Vendor'] = { title: selectedVendor[0].Vendor.factory_nickname, id: selectedVendor[0].Vendor.id }
      data['FOB Cost'] = selectedVendor[0].Price;
      var percDiff = 0;
      if (cbms.length == 2) {
        percDiff = this.getPercentageChange(cbms[0], cbms[1]);
        if (percDiff > 15) {
          this._snakcbar.open('CBM difference is more than 15%', 'close')
        } else {
          //take the avrage of the two cbms
          data['CBM/pc'] = (parseFloat(cbms[0]) + parseFloat(cbms[1])) / 2
        }
      } else if (cbms.length == 1) {
        data['CBM/pc'] = selectedVendor[0]['CBM/pc']
      } else if (this.oddOrEven(cbms.length) == 'odd') {
        data['CBM/pc'] = await this.median(cbms);

      } else if (this.oddOrEven(cbms.length) == 'even') {
        // take the average of the 2 middle numbers
        let middle = Math.floor(cbms.length / 2);
        data['CBM/pc'] = (parseFloat(cbms[middle - 1]) + parseFloat(cbms[middle])) / 2;
      }

      if (selectedVendor[0]?.['CBM/pc']) {
        data['CBM/pc'] = selectedVendor[0]['CBM/pc'];
     }

      if (data[this.getMasterFiledName('case_pack')] && data['CBM/pc'] && data['containercost']) {
        let containercost = data[this.getMasterFiledName('container_price')] ?? data['containercost'].title
        let frtCostPerCBM = parseFloat(containercost) / 60;
        let freight: any = parseFloat(data['CBM/pc']) * frtCostPerCBM
        data[this.getMasterFiledName('freight')] = freight.toFixed(7);
        data[this.getMasterFiledName('cbm_pc')] = data['CBM/pc']
        if (freight) {
          let fob_cost = data[this.getMasterFiledName('fob_cost')]
          let agent = data[this.getMasterFiledName('agent')] ? data[this.getMasterFiledName('agent')] : 0
          let duty_rate = data[this.getMasterFiledName('duty_rate')].title ? data[this.getMasterFiledName('duty_rate')].title : 0
          let duty_rate_dollar_amount = data['duty_rate_dollar_amount'] ? data['duty_rate_dollar_amount'] : 0
          let costInclDutyAgent = ((parseFloat(fob_cost) * (1 + (parseFloat(agent) / 100))) * (1 + (parseFloat(duty_rate) / 100)) + parseFloat(duty_rate_dollar_amount)).toFixed(7);
          let ldp_port = (parseFloat(costInclDutyAgent) + parseFloat(freight)).toFixed(7);
          data[this.getMasterFiledName('landed_cost')] = ldp_port
        }
      }
      ///
      await this.equation.recalculate_Lic_Gen(this.masterGridApi, this.masterColumnDefs)
      await this.itemService.updateRfqItem(data).subscribe(res => {
        this.params.api.applyTransaction({ update: [data] });
      })
    } else if (selectedVendor.length > 1) {
      this._snakcbar.open('Please select only one vendor.', 'close')
    } else {
      this._snakcbar.open('Please select a vendor.', 'close')
    }
  }

  getSelectedRowData() {
    let detailId = this.params.node.id
    let gridApi = this.params.api.getDetailGridInfo(detailId)
    if (!gridApi) {
      return [];
    }
    let selectedNodes = gridApi.api.getSelectedNodes();
    let selectedData = selectedNodes.map(node => node.data);
    return selectedData;
  }

  async median(values) {
    values.sort(function (a, b) {
      return parseFloat(a) - parseFloat(b);
    });
    var half = Math.floor(values.length / 2);

    if (values.length % 2)
      return values[half];
    else
      return (parseFloat(values[half - 1]) + parseFloat(values[half])) / 2.0;
  }

  getPercentageChange(oldNumber, newNumber) {
    var decreaseValue = parseFloat(oldNumber) - parseFloat(newNumber);

    return (decreaseValue / parseFloat(oldNumber)) * 100;
  }

  oddOrEven(x) {
    return (x & 1) ? "odd" : "even";
  }

  getContextMenuItems = (params) => {
    const menuItems = [];
    if (params.column.colDef.colId == 'note' || params.column.colDef.colId == 'vendor_note' || params.column.colDef.colId == 'cbm_pc' || params.column.colDef.colId == 'price' || params.column.colDef.colId == 'quote_price') {
      menuItems.push({
        name: 'Log History',
        action: () => {
          window['dialog'].open(AuditLogComponent, {
            disableClose: true,
            data: {
              colId: params.column.colDef.colId === 'vendor_note'
                ? 'note'
                : params.column.colDef.colId === 'quote_price'
                  ? 'price'
                  : params.column.colDef.colId,
              ref_id: params.node.data.row_id,
              vendor_id: params.node.data.Vendor.id,
              moduleName: 'rfq_detail'
            }
          });
        }
      });
    }
    // Request a fresh quote for a stale factory price. Internal sourcing/admin
    // only (vendors never see this); marks the price cell orange + emails the factory.
    const isPriceCol = params.column.colDef.colId == 'price' || params.column.colDef.colId == 'quote_price';
    const canRequestRequote =
      window['role'] === 'admin' || window['role'] === 'sourcing_manager' || window['role'] === 'production';
    if (isPriceCol && canRequestRequote && params.node?.data?.quote_id) {
      const alreadyRequested = !!params.node.data.requote_requested;
      menuItems.push({
        name: alreadyRequested ? 'New quote already requested' : 'Request new quote',
        disabled: alreadyRequested,
        action: () => {
          const data = params.node.data;
          this.itemService
            .requestRequote({ quote_id: data.quote_id, priceCode: data.priceCode })
            .subscribe((res: any) => {
              if (res?.status === 'success') {
                data.requote_requested = true;
                params.api.refreshCells({ rowNodes: [params.node], force: true });
                this._snakcbar.open('New quote requested. The factory has been emailed.', 'close');
              } else {
                this._snakcbar.open('Could not request a new quote. Please try again.', 'close');
              }
            });
        }
      });
    }
    if (window['role'] === 'admin' || window['role'] === 'production' || window['role'] === 'sourcing_manager' || window['role'] === 'sales') {
      menuItems.push({
        name: 'View Inserted Data',
        action: async () => {
          window['dataWasChanged'] = true;
            const dialogRef = window['dialog'].open(VendorDataInfoComponent, {
              data: {...params.node.data,
                checkVendor: params.node.data.Vendor.id === this.params.data['Chosen Vendor']?.id}, // check if vendor is chosen
              disableClose: true
            });
            dialogRef.afterClosed().subscribe(async (result) => {
              if (result && window['dataWasChanged']) {
                window['dataWasChanged'] = false;
                params.node.data.Price = result.data.price;
                params.node.data.carton_length = result.data.length;
                params.node.data.carton_width = result.data.width;
                params.node.data.carton_height = result.data.height;
                params.node.data.cbm_modified = true;
                params.data = params.node.data
                window['DialogData'] = true;
                window['onCellValueChanged'](params);
              }
            });
        }
      });
    }
    return menuItems;
  }
  cellMouseOver(params) {
    params.node.tooltipDisplayValue = params.value
    params.node.targetElementSrc = params.event.target
    this.cellMouseOverActive = true
    this.displayValue = params.value

  }

  cellMouseOut(params) {
    // this.cellMouseOverActive = false
    // this.displayValue = ''
  }

  /** Parse a quote price into a finite number, defaulting to 0 when unparseable. */
  private toPrice(value: any): number {
    const numValue = typeof value === 'number' ? value : parseFloat(value);
    return Number.isFinite(numValue) ? numValue : 0;
  }

  /**
   * A vendor quote row sorts to the bottom of the detail grid when it has no
   * usable price (blank / zero / negative) or the factory declined to quote
   * (req_status == 1). Used by the price default-sort comparator.
   */
  private isUnpricedOrDeclined(data: any): boolean {
    if (!data) return true;
    if (data.req_status == 1) return true;
    const price = this.toPrice(data?.['Price']);
    return price <= 0;
  }

  /**
   * Wires the detail grid's default sort: price ascending as the primary sort,
   * with unpriced/declined rows pushed to the bottom. Mutates the matching
   * colDef in place. The comparator reads the row's `Price` directly so it is
   * independent of the column's colId/field/valueGetter.
   */
  private applyDefaultPriceSort(colHeaders: any[]): void {
    if (!Array.isArray(colHeaders)) return;
    const isPriceCol = (c: any) => c?.colId === 'quote_price' || c?.colId === 'price';
    // Prefer a visible price column; fall back to any price column.
    const priceCol =
      colHeaders.find(c => isPriceCol(c) && c?.hide !== true) ||
      colHeaders.find(c => isPriceCol(c));
    if (!priceCol) return;

    priceCol.sort = 'asc';
    priceCol.sortIndex = 0;
    priceCol.comparator = (_valueA: any, _valueB: any, nodeA: any, nodeB: any) => {
      const aBottom = this.isUnpricedOrDeclined(nodeA?.data);
      const bBottom = this.isUnpricedOrDeclined(nodeB?.data);
      if (aBottom && bBottom) return 0;
      if (aBottom) return 1;
      if (bBottom) return -1;
      return this.toPrice(nodeA?.data?.['Price']) - this.toPrice(nodeB?.data?.['Price']);
    };
  }

  private convertToNumberOrNull(value: any): number | null {
    // Ensure the value is a number or null
    if (value === null || value === undefined || value === '') {
      return null;
    }
    const numValue = typeof value === 'number' ? value : parseFloat(value);
    return isNaN(numValue) ? null : numValue;
  }
}

